            for r, c in placement:
                output[r][c] = fc

        remaining = set(holes_set)
        for placement in placement_map:
            remaining -= set(placement)

        if remaining and single_cell_colors:
            for fc, count in single_cell_colors.items():
                if count == len(remaining):
                    for r, c in remaining:
                        output[r][c] = fc
                    break

    return output.tolist()

